import { useNavigate, useParams } from 'react-router-dom';
import database from '../data';

const evaluationsByStudent = database.evaluations.reduce((map, record) => {
  if (!map[record.studentId]) map[record.studentId] = [];
  map[record.studentId].push(record);
  return map;
}, {});

const studentDetailsByStudent = database.student_details.reduce((map, record) => {
  map[record.studentId] = record;
  return map;
}, {});

function StudentDetails() {
  const { studentId } = useParams();
  const navigate = useNavigate();
  const student = database.students.find((item) => item.studentId === studentId);
  const detail = studentDetailsByStudent[studentId];
  const evaluations = evaluationsByStudent[studentId] || [];

  if (!student) {
    return (
      <div className="container py-5">
        <div className="alert alert-warning">Student with ID {studentId} not found.</div>
        <button className="btn btn-secondary" onClick={() => navigate('/')}>Back to Home</button>
      </div>
    );
  }

  return (
    <div className="container py-4">
      <div className="mb-3">
        <button className="btn btn-success" onClick={() => navigate('/')}>Back to Home</button>
      </div>
      <div className="card p-4">
        <h4>{student.name}'s Grade Details:</h4>
        <div className="row mt-3">
          <div className="col-md-6 mb-3">
            <div className="border rounded p-3">
              <p className="mb-1"><strong>StudentId:</strong> {student.studentId}</p>
              <p className="mb-1"><strong>Name:</strong> {student.name}</p>
              <p className="mb-1"><strong>Age:</strong> {student.age}</p>
              <p className="mb-1"><strong>Status:</strong> {student.isRegularStudent ? 'Fulltime' : 'Applicant'}</p>
            </div>
          </div>
          <div className="col-md-6 mb-3">
            <div className="border rounded p-3">
              <p className="mb-1"><strong>Street:</strong> {detail?.address?.street || 'N/A'}</p>
              <p className="mb-1"><strong>City:</strong> {detail?.address?.city || 'N/A'}</p>
            </div>
          </div>
        </div>
        <div className="table-responsive">
          <table className="table table-striped table-bordered">
            <thead>
              <tr>
                <th>Grade</th>
                <th>Explanation</th>
              </tr>
            </thead>
            <tbody>
              {evaluations.length > 0 ? (
                evaluations.map((record) => (
                  <tr key={record.id}>
                    <td>{record.grade}</td>
                    <td>{record.additionalExplanation}</td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan={2} className="text-center">No grades available.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

export default StudentDetails;
